const enabled = ($env['FEATURE_STATUS_NOTIFICATIONS'] || 'true').toLowerCase();
if (enabled !== 'true' && enabled !== '1') {
  console.log('[status-notif] FEATURE_STATUS_NOTIFICATIONS desabilitado — pulando');
  return [];
}
return [{ json: { feature_enabled: true } }];

const rows = $input.all();
console.log(`[status-notif] ${rows.length} pedido(s) para notificar`);
if (!rows || rows.length === 0) return [];
return rows;

const o = $json;
const nome = o.customer_name || 'cliente';
const nomeCapit = nome.charAt(0).toUpperCase() + nome.slice(1);
const tipoLabel = o.order_type === 'delivery' ? 'Delivery' : o.order_type === 'retirada' ? 'Retirada' : 'Mesa';

if (!o.message_template) {
  console.log(`[status-notif] Sem template para status '${o.status}' — pulando`);
  return [];
}

const msg = o.message_template
  .replace(/\{name\}/g, nomeCapit)
  .replace(/\{code\}/g, o.code)
  .replace(/\{order_type\}/g, tipoLabel)
  .replace(/\\n/g, '\n');

return [{ json: { ...o, msg } }];

const { customer_phone, msg, evolution_api_key, status } = $json;
const instancia = $env['EVOLUTION_INSTANCE'] || 'default';
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `http://evolution_api:8080/message/sendText/${instancia}`,
    headers: { 'Content-Type': 'application/json', 'apikey': evolution_api_key || '' },
    body: JSON.stringify({ number: customer_phone, text: msg })
  });
  console.log(`[status-notif] Enviado para ${customer_phone} — status: ${status}`);
} catch(e) {
  console.log(`[status-notif] Erro ao enviar para ${customer_phone}:`, e.message);
}
return [{ json: $json }];
